mapper.select:
/*AcenCnsltSrMapper.selectAcenCnsltConSrListExcel*/ SELECT TO_CHAR(MST.TALK_DT, 'YYYY-MM-DD') AS TALK_DT ,FN_GET_CODENM('ACEN0010', MST.TALK_TYPE) AS TALK_TYPE ,MST.CNSLT_TYPE_FIR_NM ,MST.CNSLT_TYPE_SEC_NM ,MST.CNSLT_TYPE_THI_NM ,MST.CNSLT_TYPE_DTL_NM ,TO_CHAR(MST.TALK_STRT_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS TALK_STRT_DTTM ,TO_CHAR(MST.TALK_END_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS TALK_END_DTTM ,MST.TALK_TOTAL_TIME ,MST.ACW_TOTAL_TIME ,CASE WHEN LENGTH(MST.TALK_TEL_NO) = 11 THEN SUBSTR(MST.TALK_TEL_NO, 1, 3) || '-' || SUBSTR(MST.TALK_TEL_NO, 4, 4) || '-' || SUBSTR(MST.TALK_TEL_NO, 8, 4) WHEN LENGTH(MST.TALK_TEL_NO) = 10 THEN SUBSTR(MST.TALK_TEL_NO, 1, 3) || '-' || SUBSTR(MST.TALK_TEL_NO, 4, 3) || '-' || SUBSTR(MST.TALK_TEL_NO, 7, 4) ELSE '' END AS TALK_TEL_NO ,CASE WHEN LENGTH(SUB.SUBSCRIBER_NO) = 11 THEN SUBSTR(SUB.SUBSCRIBER_NO, 1, 3) || '-' || SUBSTR(SUB.SUBSCRIBER_NO, 4, 4) || '-' || SUBSTR(SUB.SUBSCRIBER_NO, 8, 4) WHEN LENGTH(SUB.SUBSCRIBER_NO) = 10 THEN SUBSTR(SUB.SUBSCRIBER_NO, 1, 3) || '-' || SUBSTR(SUB.SUBSCRIBER_NO, 4, 3) || '-' || SUBSTR(SUB.SUBSCRIBER_NO, 7, 4) ELSE '' END AS CTN ,DTL.CONTRACT_NUM ,MST.CUSTOMER_NO ,FN_GET_USRNM(MST.CNSLT_MID) AS CNSLT_NM ,MST.TALK_NM ,SUB.SUB_LINK_NAME AS CSTMR_NM ,FN_GET_CODENM('ACEN0011', MST.TALK_RESULT_CODE) AS TALK_RESULT_CODE ,DECODE(DTL.AGE, 0, '', DTL.AGE) AS AGE ,DTL.BIRTH_DT ,DTL.GENDER ,DTL.DATA_TYPE ,NVL2(DTL.OPEN_AGNT_CD, FN_GET_ORGNM(DTL.OPEN_AGNT_CD) || '/' || DTL.OPEN_AGNT_CD, '') AS OPEN_AGNT ,FN_GET_CODENM('MSP0003', DTL.SUB_STATUS) AS SUB_STATUS_NM ,TO_CHAR(TO_DATE(DTL.LST_COM_ACTV_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE ,TO_CHAR(TO_DATE(DTL.CANCEL_DATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD') AS CANCEL_DATE ,TO_CHAR(TO_DATE(DTL.STOP_DATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD') AS STOP_DATE ,FN_GET_CODENM('RCP9001', DTL.OPER_TYPE) AS OPER_TYPE ,FN_GET_CODENM('RCP9004', DTL.REQ_BUY_TYPE) AS REQ_BUY_TYPE ,FN_GET_ORGNM(DTL.FST_USIM_ORG_ID) AS FST_USIM_ORG ,FN_GET_ORGNM(DTL.USIM_ORG_ID) AS USIM_ORG ,RATE.RATE_NM ,DTL.MRKT_AGREE_YN ,CASE WHEN DTL.USIM_TYPE = 'E' THEN 'Y' WHEN DTL.USIM_TYPE = 'U' THEN 'N' ELSE '' END AS USIM_KINDS_CD ,FN_GET_ACEN_CNSLT_CONTENT@DL_MCP(MST.CNSLT_SEQ, 1, 1000) AS CNSLT_CONTENT ,FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE FROM NMCP_ACEN_CNSLT_MST@DL_MCP MST ,NMCP_ACEN_CNSLT_DTL@DL_MCP DTL ,MSP_JUO_SUB_INFO SUB ,MSP_RATE_MST RATE WHERE MST.CNSLT_SEQ = DTL.CNSLT_SEQ AND DTL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND DTL.RATE_CD = RATE.RATE_CD(+) AND MST.TALK_DT BETWEEN TO_DATE(#{callStrtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{callEndDt} || '235959', 'YYYYMMDDHH24MISS') AND MST.TALK_YM BETWEEN SUBSTR(#{callStrtDt}, 1, 6) AND SUBSTR(#{callEndDt}, 1, 6) /*상담사ID*/
AND MST.CNSLT_ID = #{searchCnsltId}
/*SR(대)*/
AND MST.CNSLT_TYPE_FIR_NM LIKE '%' || #{searchSrFir} || '%'
/*SR(중)*/
AND MST.CNSLT_TYPE_SEC_NM LIKE '%' || #{searchSrSec} || '%'
/*SR(소)*/
AND MST.CNSLT_TYPE_THI_NM LIKE '%' || #{searchSrThi} || '%'
/*SR(세)*/
AND MST.CNSLT_TYPE_DTL_NM LIKE '%' || #{searchSrDtl} || '%'
/*통화유형*/
AND MST.TALK_TYPE = #{searchTalkType}
/*검색구분(계약번호)*/
AND (DTL.CONTRACT_NUM = #{searchVal} OR DTL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchVal}))
/*검색구분-CTN*/
AND SUB.SUBSCRIBER_NO = #{searchVal}
/*검색구분-요금제*/
AND RATE.RATE_NM LIKE '%' || #{searchVal} || '%'
/*검색구분-고객명*/
AND UPPER(SUB.SUB_LINK_NAME) LIKE UPPER(#{searchVal}) || '%'
ORDER BY MST.TALK_DT DESC, MST.CNSLT_SEQ DESC

/*AcenCnsltSrMapper.selectAcenCnsltSrListExcel*/ SELECT TO_CHAR(MST.TALK_DT, 'YYYY-MM-DD') AS TALK_DT ,FN_GET_CODENM('ACEN0010', MST.TALK_TYPE) AS TALK_TYPE ,MST.CNSLT_TYPE_FIR_NM ,MST.CNSLT_TYPE_SEC_NM ,MST.CNSLT_TYPE_THI_NM ,MST.CNSLT_TYPE_DTL_NM ,TO_CHAR(MST.TALK_STRT_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS TALK_STRT_DTTM ,TO_CHAR(MST.TALK_END_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS TALK_END_DTTM ,MST.TALK_TOTAL_TIME ,MST.ACW_TOTAL_TIME ,CASE WHEN LENGTH(MST.TALK_TEL_NO) = 11 THEN SUBSTR(MST.TALK_TEL_NO, 1, 3) || '-' || SUBSTR(MST.TALK_TEL_NO, 4, 4) || '-' || SUBSTR(MST.TALK_TEL_NO, 8, 4) WHEN LENGTH(MST.TALK_TEL_NO) = 10 THEN SUBSTR(MST.TALK_TEL_NO, 1, 3) || '-' || SUBSTR(MST.TALK_TEL_NO, 4, 3) || '-' || SUBSTR(MST.TALK_TEL_NO, 7, 4) ELSE '' END AS TALK_TEL_NO ,CASE WHEN LENGTH(SUB.SUBSCRIBER_NO) = 11 THEN SUBSTR(SUB.SUBSCRIBER_NO, 1, 3) || '-' || SUBSTR(SUB.SUBSCRIBER_NO, 4, 4) || '-' || SUBSTR(SUB.SUBSCRIBER_NO, 8, 4) WHEN LENGTH(SUB.SUBSCRIBER_NO) = 10 THEN SUBSTR(SUB.SUBSCRIBER_NO, 1, 3) || '-' || SUBSTR(SUB.SUBSCRIBER_NO, 4, 3) || '-' || SUBSTR(SUB.SUBSCRIBER_NO, 7, 4) ELSE '' END AS CTN ,DTL.CONTRACT_NUM ,MST.CUSTOMER_NO ,FN_GET_USRNM(MST.CNSLT_MID) AS CNSLT_NM ,MST.TALK_NM ,SUB.SUB_LINK_NAME AS CSTMR_NM ,FN_GET_CODENM('ACEN0011', MST.TALK_RESULT_CODE) AS TALK_RESULT_CODE ,DECODE(DTL.AGE, 0, '', DTL.AGE) AS AGE ,DTL.BIRTH_DT ,DTL.GENDER ,DTL.DATA_TYPE ,NVL2(DTL.OPEN_AGNT_CD, FN_GET_ORGNM(DTL.OPEN_AGNT_CD) || '/' || DTL.OPEN_AGNT_CD, '') AS OPEN_AGNT ,FN_GET_CODENM('MSP0003', DTL.SUB_STATUS) AS SUB_STATUS_NM ,TO_CHAR(TO_DATE(DTL.LST_COM_ACTV_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE ,TO_CHAR(TO_DATE(DTL.CANCEL_DATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD') AS CANCEL_DATE ,TO_CHAR(TO_DATE(DTL.STOP_DATE, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD') AS STOP_DATE ,FN_GET_CODENM('RCP9001', DTL.OPER_TYPE) AS OPER_TYPE ,FN_GET_CODENM('RCP9004', DTL.REQ_BUY_TYPE) AS REQ_BUY_TYPE ,FN_GET_ORGNM(DTL.FST_USIM_ORG_ID) AS FST_USIM_ORG ,FN_GET_ORGNM(DTL.USIM_ORG_ID) AS USIM_ORG ,RATE.RATE_NM ,DTL.MRKT_AGREE_YN ,CASE WHEN DTL.USIM_TYPE = 'E' THEN 'Y' WHEN DTL.USIM_TYPE = 'U' THEN 'N' ELSE '' END AS USIM_KINDS_CD ,FN_GET_CODENM('RCP0007', DTL.ON_OFF_TYPE) AS ON_OFF_TYPE FROM NMCP_ACEN_CNSLT_MST@DL_MCP MST ,NMCP_ACEN_CNSLT_DTL@DL_MCP DTL ,MSP_JUO_SUB_INFO SUB ,MSP_RATE_MST RATE WHERE MST.CNSLT_SEQ = DTL.CNSLT_SEQ AND DTL.CONTRACT_NUM = SUB.CONTRACT_NUM(+) AND DTL.RATE_CD = RATE.RATE_CD(+) AND MST.TALK_DT BETWEEN TO_DATE(#{callStrtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{callEndDt} || '235959', 'YYYYMMDDHH24MISS') AND MST.TALK_YM BETWEEN SUBSTR(#{callStrtDt}, 1, 6) AND SUBSTR(#{callEndDt}, 1, 6) /*상담사ID*/
AND MST.CNSLT_ID = #{searchCnsltId}
/*SR(대)*/
AND MST.CNSLT_TYPE_FIR_NM LIKE '%' || #{searchSrFir} || '%'
/*SR(중)*/
AND MST.CNSLT_TYPE_SEC_NM LIKE '%' || #{searchSrSec} || '%'
/*SR(소)*/
AND MST.CNSLT_TYPE_THI_NM LIKE '%' || #{searchSrThi} || '%'
/*SR(세)*/
AND MST.CNSLT_TYPE_DTL_NM LIKE '%' || #{searchSrDtl} || '%'
/*통화유형*/
AND MST.TALK_TYPE = #{searchTalkType}
/*검색구분(계약번호)*/
AND (DTL.CONTRACT_NUM = #{searchVal} OR DTL.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchVal}))
/*검색구분-CTN*/
AND SUB.SUBSCRIBER_NO = #{searchVal}
/*검색구분-요금제*/
AND RATE.RATE_NM LIKE '%' || #{searchVal} || '%'
/*검색구분-고객명*/
AND UPPER(SUB.SUB_LINK_NAME) LIKE UPPER(#{searchVal}) || '%'
ORDER BY MST.TALK_DT DESC, MST.CNSLT_SEQ DESC

/*AcenCnsltSrMapper.selectAcenCnsltSrStatsListExcel*/ SELECT TO_CHAR(TO_DATE(TALK_YM, 'YYYYMM'), 'YYYY-MM') AS TALK_YM ,CNSLT_TYPE_FIR_NM ,CNSLT_TYPE_SEC_NM ,CNSLT_TYPE_THI_NM ,CNSLT_TYPE_DTL_NM ,COUNT(CNSLT_SEQ) AS TOTAL_CNT FROM NMCP_ACEN_CNSLT_MST@DL_MCP WHERE TALK_DT BETWEEN TO_DATE(#{strtDttm} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{endDttm} || '235959', 'YYYYMMDDHH24MISS') AND TALK_YM BETWEEN #{strtDt} AND #{endDt} /*SR(대)*/
AND CNSLT_TYPE_FIR_NM LIKE '%' || #{searchSrFir} || '%'
/*SR(중)*/
AND CNSLT_TYPE_SEC_NM LIKE '%' || #{searchSrSec} || '%'
/*SR(소)*/
AND CNSLT_TYPE_THI_NM LIKE '%' || #{searchSrThi} || '%'
/*상세*/
AND CNSLT_TYPE_DTL_NM LIKE '%' || #{searchSrDtl} || '%'
GROUP BY TALK_YM, CNSLT_TYPE_FIR_NM, CNSLT_TYPE_SEC_NM, CNSLT_TYPE_THI_NM, CNSLT_TYPE_DTL_NM ORDER BY TALK_YM DESC
